121→func TestRunGenMake_WithDependencies(t *testing.T) {
122→	tmp := t.TempDir()
123→	tasksPath := filepath.Join(tmp, "tasks.yaml")
124→	outPath := filepath.Join(tmp, "targets.mk")
125→
126→	yaml := `- id: alpha
127→  prompt: prompts/alpha.md
128→  needs: []
129→
130→- id: beta
131→  prompt: prompts/beta.md
132→  needs:
133→    - alpha
134→
135→- id: gamma
136→  prompt: prompts/gamma.md
137→  needs:
138→    - alpha
139→    - beta
140→`
141→	os.WriteFile(tasksPath, []byte(yaml), 0o644)
142→
143→	err := runGenMake([]string{"--tasks", tasksPath, "--out", outPath})
144→	if err != nil {
145→		t.Fatalf("unexpected error: %v", err)
146→	}
147→
148→	data, err := os.ReadFile(outPath)
149→	if err != nil {
150→		t.Fatalf("failed to read output: %v", err)
151→	}
152→	got := string(data)
153→
154→	// all target should list all three in definition order
155→	if !strings.Contains(got, "all: .kiln/done/alpha.done .kiln/done/beta.done .kiln/done/gamma.done") {
156→		t.Errorf("all target incorrect, got:\n%s", got)
157→	}
158→
159→	// alpha has no deps
160→	if !strings.Contains(got, ".kiln/done/alpha.done:\n") {
161→		t.Error("alpha should have no prerequisites")
162→	}
163→
164→	// beta depends on alpha
165→	if !strings.Contains(got, ".kiln/done/beta.done: .kiln/done/alpha.done\n") {
166→		t.Error("beta should depend on alpha")
167→	}
168→
169→	// gamma depends on alpha and beta
170→	if !strings.Contains(got, ".kiln/done/gamma.done: .kiln/done/alpha.done .kiln/done/beta.done\n") {
171→		t.Error("gamma should depend on alpha and beta")
172→	}
173→}
