175→func TestRunGenMake_DeterministicOutput(t *testing.T) {
176→	tmp := t.TempDir()
177→	tasksPath := filepath.Join(tmp, "tasks.yaml")
178→
179→	yaml := `- id: zulu
180→  prompt: z.md
181→  needs: []
182→
183→- id: alpha
184→  prompt: a.md
185→  needs: []
186→
187→- id: mike
188→  prompt: m.md
189→  needs:
190→    - zulu
191→`
192→	os.WriteFile(tasksPath, []byte(yaml), 0o644)
193→
194→	// Run twice and compare output
195→	out1 := filepath.Join(tmp, "out1.mk")
196→	out2 := filepath.Join(tmp, "out2.mk")
197→
198→	if err := runGenMake([]string{"--tasks", tasksPath, "--out", out1}); err != nil {
199→		t.Fatalf("run 1 failed: %v", err)
200→	}
201→	if err := runGenMake([]string{"--tasks", tasksPath, "--out", out2}); err != nil {
202→		t.Fatalf("run 2 failed: %v", err)
203→	}
204→
205→	d1, _ := os.ReadFile(out1)
206→	d2, _ := os.ReadFile(out2)
207→	if string(d1) != string(d2) {
208→		t.Errorf("non-deterministic output:\nrun1:\n%s\nrun2:\n%s", d1, d2)
209→	}
210→
211→	// Verify definition order preserved (zulu before alpha before mike)
212→	got := string(d1)
213→	zIdx := strings.Index(got, ".kiln/done/zulu.done:")
214→	aIdx := strings.Index(got, ".kiln/done/alpha.done:")
215→	mIdx := strings.Index(got, ".kiln/done/mike.done:")
216→	if zIdx >= aIdx || aIdx >= mIdx {
217→		t.Errorf("targets not in definition order: z=%d a=%d m=%d", zIdx, aIdx, mIdx)
218→	}
219→}
