296→// fakeCommandBuilder returns a commandBuilder that runs a helper process
297→// instead of the real claude binary. The helper process behaviour is
298→// controlled by the env var KILN_TEST_HELPER_MODE.
299→func fakeCommandBuilder(mode string) func(context.Context, string) *exec.Cmd {
300→	return func(ctx context.Context, prompt string) *exec.Cmd {
301→		cmd := exec.CommandContext(ctx, os.Args[0], "-test.run=TestHelperProcess", "--", prompt)
302→		cmd.Env = append(os.Environ(), "KILN_TEST_HELPER_MODE="+mode)
303→		return cmd
304→	}
305→}
