307→// TestHelperProcess is invoked as a subprocess by the fake command builder.
308→// It is not a real test — the guard at the top prevents it from running
309→// as part of the normal test suite.
310→func TestHelperProcess(t *testing.T) {
311→	mode := os.Getenv("KILN_TEST_HELPER_MODE")
312→	if mode == "" {
313→		return // not invoked as a helper
314→	}
315→
316→	switch mode {
317→	case "success":
318→		// Echo the prompt back as fake stream-json output
319→		args := os.Args
320→		for i, a := range args {
321→			if a == "--" {
322→				if i+1 < len(args) {
323→					os.Stdout.WriteString(`{"type":"assistant","content":"` + args[i+1] + `"}` + "\n")
324→				}
325→				break
326→			}
327→		}
328→		os.Exit(0)
329→	case "fail":
330→		os.Stderr.WriteString("error: something went wrong\n")
331→		os.Exit(1)
332→	case "hang":
333→		// Sleep for a long time; will be killed by context timeout.
334→		time.Sleep(1 * time.Hour)
335→		os.Exit(0)
336→	default:
337→		os.Stderr.WriteString("unknown helper mode\n")
338→		os.Exit(2)
339→	}
340→}
