	// Verify definition order preserved (zulu before alpha before mike)
	got := string(d1)
	zIdx := strings.Index(got, ".kiln/done/zulu.done:")
	aIdx := strings.Index(got, ".kiln/done/alpha.done:")
	mIdx := strings.Index(got, ".kiln/done/mike.done:")
